class Pagination{constructor(t){this.items=t,this.currentPage=0}get maxLength(){return this.items.length-1}get hasPrev(){return this.currentPage>0}get hasNext(){return this.currentPage<this.maxLength}get current(){return this.items[this.currentPage]}get next(){if(!this.hasNext)throw new RangeError("No next page available");return this.currentPage+=1,this.items[this.currentPage]}get prev(){if(!this.hasPrev)throw new RangeError("No previous page available");return this.currentPage-=1,this.items[this.currentPage]}get peekNext(){return this.hasNext?this.items[this.currentPage+1]:null}get peekPrev(){return this.hasPrev?this.items[this.currentPage-1]:null}}const escapeButton=t=>{"Escape"===t.key&&(document.body.innerHTML="",location.href="https://taiko.bui.pm/")},copyText=t=>{navigator.clipboard.writeText(t).then((function(){alert("Copied to clipboard!")}),(function(){alert("Failed to copy.")}))};export{Pagination,escapeButton,copyText};